import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

function Profile() {
  const [user, setUser] = useState(null);
  const [profile, setProfile] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({});
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem("access");
    if (!token) navigate("/");
    else fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const token = localStorage.getItem('access');
      const userRes = await axios.get('http://127.0.0.1:8000/api/users/me/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      const profileRes = await axios.get('http://127.0.0.1:8000/api/users/profile/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUser(userRes.data);
      setProfile(profileRes.data);
      setFormData(profileRes.data);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('access');
      await axios.patch('http://127.0.0.1:8000/api/users/profile/', formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      alert('Profile updated!');
      setIsEditing(false);
      fetchProfile();
    } catch (error) {
      alert('Update failed');
    }
  };

  if (!profile) return <div>Loading...</div>;

  return (
    <div className="profile-container">
      <h2>My Profile</h2>
      {!isEditing ? (
        <div>
          <p><strong>Name:</strong> {profile.full_name || user?.username}</p>
          <p><strong>Email:</strong> {user?.email}</p>
          <p><strong>Role:</strong> {user?.role}</p>
          <p><strong>Bio:</strong> {profile.bio || 'Not provided'}</p>
          <p><strong>Skills:</strong> {profile.skills || 'Not provided'}</p>
          <p><strong>Location:</strong> {profile.location || 'Not provided'}</p>
          <button onClick={() => setIsEditing(true)}>Edit Profile</button>
        </div>
      ) : (
        <form onSubmit={handleSubmit}>
          <input name="full_name" placeholder="Full Name" value={formData.full_name || ''} onChange={(e) => setFormData({ ...formData, full_name: e.target.value })} />
          <textarea name="bio" placeholder="Bio" value={formData.bio || ''} onChange={(e) => setFormData({ ...formData, bio: e.target.value })} />
          <input name="skills" placeholder="Skills (comma separated)" value={formData.skills || ''} onChange={(e) => setFormData({ ...formData, skills: e.target.value })} />
          <input name="location" placeholder="Location" value={formData.location || ''} onChange={(e) => setFormData({ ...formData, location: e.target.value })} />
          <button type="submit">Save</button>
          <button type="button" onClick={() => setIsEditing(false)}>Cancel</button>
        </form>
      )}
      <button onClick={() => navigate(-1)}>Back</button>
    </div>
  );
}

export default Profile;
